/*
 * Base exception definitions
 *
 *                      Error (JavaScript native exception class)
 *                        ^
 *                        * 
 *              *********************
 *              *                   *
 *       BusniessException   SystemException
 *            *                      ^
 *            *                      *
 *            *                      *****************************************************************
 *            *                       *                      *                 *              *
 *   UpdateLockedException  ConfigurationException  RetryableException  SecurityException DataException
 */
  
 
/*
 * BusinessException
 * Not thrown by code in the client framework but may be generated by server side components executing 
 * validation logic (especially if that validation is not replicated in the client). These exceptions will 
 * be propagated across the web services layer and thrown as JavaScript exceptions by the SOAP interface 
 * for propagation up to the application code.
 *
 * @param message The exception message
 * @causedBy Optional exception that caused this exception to be thrown
 * @exceptionHierarchy Optional array denoting the exception class hierarchy (should be used when 
 * exceptions are passed between contexts, i.e. when an exception is propagted across the SOAP
 * interface
 */
function BusinessException(message, causedBy, exceptionHierarchy)
{
   this.message = message;
   //this.m_rootCause = causedBy;
   this.m_rootCause = causedBy;
   
   if(undefined == exceptionHierarchy)
   {
      this.exceptionHierarchy = new Array('Error','BusinessException');
   }
   else
   {
      this.exceptionHierarchy = exceptionHierarchy;
   }
   this.name = 'BusinessException';
}
BusinessException.prototype = new fwException()
BusinessException.prototype.constructor = BusinessException;

/*
 * TestBusinessException
 * Not thrown by code in the client framework but may be generated by server side components during testing
 *
 * @param message The exception message
 * @causedBy Optional exception that caused this exception to be thrown
 * @exceptionHierarchy Optional array denoting the exception class hierarchy (should be used when 
 * exceptions are passed between contexts, i.e. when an exception is propagted across the SOAP
 * interface
 */
function TestBusinessException(message, causedBy, exceptionHierarchy)
{
   this.message = message;
   this.m_rootCause = causedBy;
   
   if(undefined == exceptionHierarchy)
   {
      this.exceptionHierarchy = new Array('Error','BusinessException', 'TestBusinessException');
   }
   else
   {
      this.exceptionHierarchy = exceptionHierarchy;
   }
   this.name = 'TestBusinessException';
}
TestBusinessException.prototype = new BusinessException()
TestBusinessException.prototype.constructor = TestBusinessException;

/*
 * SystemException
 * Generic exception indicating a failure within the framework. Specialist exception classes 
 * exist below this in the hierarchy which should be used if applicable. Errors that occur 
 * within the framework but do not match any of the specialist cases should be thrown as a 
 * SystemException. These exceptions are fatal and further application processing should be prevented.
 *
 * @param message The exception message
 * @causedBy Optional exception that caused this exception to be thrown
 * @exceptionHierarchy Optional array denoting the exception class hierarchy (should be used when 
 * exceptions are passed between contexts, i.e. when an exception is propagted across the SOAP
 * interface 
 */
function SystemException(message, causedBy, exceptionHierarchy)
{
   this.message = message;
   this.m_rootCause = causedBy;
   
   if(undefined == exceptionHierarchy)
   {
      this.exceptionHierarchy = new Array('Error','SystemException');
   }
   else
   {
      this.exceptionHierarchy = exceptionHierarchy;
   }
   this.name = 'SystemException';
}
SystemException.prototype = new fwException()
SystemException.prototype.constructor = SystemException;

/*
 * UpdateLockedException
 * Thrown by server side code when the database mapping layer detects that optimistic locking 
 * has been violated by an update. This is propagated back across web services and raised by 
 * the SOAP interface as a JavaScript exception of the same named class.
 *
 * @param message The exception message
 * @causedBy Optional exception that caused this exception to be thrown
 * @exceptionHierarchy Optional array denoting the exception class hierarchy (should be used when 
 * exceptions are passed between contexts, i.e. when an exception is propagted across the SOAP
 * interface
 */
function UpdateLockedException(message, causedBy, exceptionHierarchy)
{
   this.message = message;
   this.m_rootCause = causedBy;
   
   if(undefined == exceptionHierarchy)
   {
      this.exceptionHierarchy = new Array('Error','BusinessException','UpdateLockedException');
   }
   else
   {
      this.exceptionHierarchy = exceptionHierarchy;
   }
   this.name = 'UpdateLockedException';
}
UpdateLockedException.prototype = new BusinessException()
UpdateLockedException.prototype.constructor = UpdateLockedException;

/*
 * ConfigurationException
 * Thrown by client and server side framework code when an error occurs that indicates 
 * that the application has configured the framework incorrectly. The response to this class 
 * of exception is the same as to that of a SystemException, i.e. it is fatal and further 
 * application execution should be halted. The way in which the error is reported may differ 
 * as the support response may well be different, especially during application development.
 *
 * @param message The exception message
 * @causedBy Optional exception that caused this exception to be thrown
 * @exceptionHierarchy Optional array denoting the exception class hierarchy (should be used when 
 * exceptions are passed between contexts, i.e. when an exception is propagted across the SOAP
 * interface
 */
function ConfigurationException(message, causedBy, exceptionHierarchy)
{
   this.message = message;
   this.m_rootCause = causedBy;
   
   if(undefined == exceptionHierarchy)
   {
      this.exceptionHierarchy = new Array('Error','SystemException','ConfigurationException');
   }
   else
   {
      this.exceptionHierarchy = exceptionHierarchy;
   }
   this.name = 'ConfigurationException';
}
ConfigurationException.prototype = new SystemException()
ConfigurationException.prototype.constructor = ConfigurationException;

/*
 * SecurityException
 * Thrown when the users credentials are rejected either during the sign on procedure or 
 * upon a request for a server side service. This exception will always be initiated by 
 * a server side component but may be propagated across the web service interface and 
 * raised by the SOAP client side interface in a different way to other server side 
 * exceptions dependant on the implementation.
 *
 * @param message The exception message
 * @causedBy Optional exception that caused this exception to be thrown
 * @exceptionHierarchy Optional array denoting the exception class hierarchy (should be used when 
 * exceptions are passed between contexts, i.e. when an exception is propagted across the SOAP
 * interface
 */
function SecurityException(message, causedBy, exceptionHierarchy)
{
   this.message = message;
   this.m_rootCause = causedBy;
   
   if(undefined == exceptionHierarchy)
   {
      this.exceptionHierarchy = new Array('Error','SystemException','SecurityException');
   }
   else
   {
      this.exceptionHierarchy = exceptionHierarchy;
   }
   this.name = 'SecurityException';
}

SecurityException.prototype = new SystemException()
SecurityException.prototype.constructor = SecurityException; 

/*
 * RetryableException
 * Thrown by client and server side framework code when an error occurs that may be transient.
 * The intention is that application code or default framework code can implement retry 
 * logic upon interception of these exceptions. Examples include the server not responding 
 * at all to a client request for a web service or the database refusing connections.
 *
 * @param message The exception message
 * @causedBy Optional exception that caused this exception to be thrown
 * @exceptionHierarchy Optional array denoting the exception class hierarchy (should be used when 
 * exceptions are passed between contexts, i.e. when an exception is propagted across the SOAP
 * interface
 */
function RetryableException(message, causedBy, exceptionHierarchy)
{
   this.message = message;
   this.m_rootCause = causedBy;
   
   if(undefined == exceptionHierarchy)
   {
      this.exceptionHierarchy = new Array('Error','SystemException','RetryableException');
   }
   else
   {
      this.exceptionHierarchy = exceptionHierarchy;
   }
   this.name = 'RetryableException';
}

RetryableException.prototype = new SystemException()
RetryableException.prototype.constructor = RetryableException; 

