/**
 * Exception thrown when an Http connection error occurs and
 *
 * 1) the response status code corresponds to one of the error codes
 *    specified in the Http connection error retry response section
 *    of the application configuration file and the value of the attribute
 *    retry is "true", or one of the default retry
 *    codes 12030 and 12152
 *
 * 2) the service call result handler includes a handler for HttpConnectionExceptions
 *
 * This exception is intended to enable the SUPS applications to handle connection
 * errors in the most appropriate manner.
 *
*/
function HttpConnectionException(message, causedBy, exceptionHierarchy)
{
   this.message = message;
   this.m_rootCause = causedBy;
   
   if(undefined == exceptionHierarchy)
   {
      this.exceptionHierarchy = new Array('Error','SystemException','HttpConnectionException');
   }
   else
   {
      this.exceptionHierarchy = exceptionHierarchy;
   }
   this.name = 'HttpConnectionException';
   
   this.m_responseStatus = null;
}

HttpConnectionException.prototype = new SystemException()
HttpConnectionException.prototype.constructor = HttpConnectionException;

/**
 * Method is a mutator method for the instance member m_responseStatus.
 *
 * @param responseStatus The response status code associated with the Http
 *                       connection exception.
 *
*/
HttpConnectionException.prototype.setResponseStatus = function( responseStatus )
{
    this.m_responseStatus = responseStatus;
}

/**
 * Method is a selector method for the instance member m_responseStatus.
 *
 * @returns Returns the value of the instance member m_responseStatus.
 *
*/
HttpConnectionException.prototype.getResponseStatus = function()
{
    return this.m_responseStatus;
}
